// Split into matched (with project) and unmatched
const items = $input.all();
const matched = [];

for (const item of items) {
  const d = item.json;
  if (!d.project_id) continue;

  const fileIds = typeof d.file_ids === 'string' ? JSON.parse(d.file_ids) : (d.file_ids || []);

  for (const fid of fileIds) {
    matched.push({
      json: {
        file_id: fid,
        project_id: d.project_id,
        doc_type: d.doc_type,
        event_id: d.event_id,
        superchat_message_id: d.superchat_message_id
      }
    });
  }
}

return matched;

// Collect unmatched events to mark as failed
const items = $input.all();
const failed = items.filter(i => !i.json.project_id);

if (failed.length === 0) return [];

return failed.map(i => ({
  json: {
    event_id: i.json.event_id,
    doc_type: i.json.doc_type || 'UNKNOWN',
    subject: (i.json.subject || '').replace(/'/g, )
  }
}));

const projectId = $('🔀 Split Matched Files').first().json.project_id;
const docType = $('🔀 Split Matched Files').first().json.doc_type;
const fileName = $('📎 Get File Info').first().json.name || 'dokument.pdf';
const mimeType = $('📎 Get File Info').first().json.mime_type || 'application/pdf';
const fileSize = $('📎 Get File Info').first().json.size || 0;

const safe = fileName
  .normalize('NFD').replace(/[̀-ͯ]/g, '')
  .replace(/[aeAE]/g, 'ae').replace(/[oeOE]/g, 'oe').replace(/[ueUE]/g, 'ue').replace(/[ss]/g, 'ss')
  .replace(/s+/g, '_').replace(/[^a-zA-Z0-9._-]/g, '');

const folderMap = {
  'MAGICPLAN': '03_Aufmass',
  'PROJECT_ORDER': '01_Auftrag',
  'INVOICE_IN': '04_Rechnung',
  'CREDIT_NOTE': '04_Rechnung',
  'BID_REQUEST': '02_Angebot',
  'REMINDER': '08_Kommunikation'
};
const folder = folderMap[docType] || '09_Sonstiges';
const storagePath = 'documents/' + projectId + '/' + folder + '/' + Date.now() + '_' + safe;

return [{ json: { project_id: projectId, doc_type: docType, file_name: fileName, storage_path: storagePath, mime_type: mimeType, file_size: fileSize, event_id: $('🔀 Split Matched Files').first().json.event_id, superchat_message_id: $('🔀 Split Matched Files').first().json.superchat_message_id }, binary: $binary }];
